js_content = "function addRow(data, index, bodyId) {
  var tbody = $('#' + bodyId);
  if (tbody.length === 0) {
    console.error('Table body not found');
    return;
  }

  var exColCount = tbody.find('tr first').length > 0 ? tbody.find('tr:first td').length : 0;
  if (exColCount === 0) {
    // Fallback to check header if body is empty
    exColCount = $('table thead tr:first th').length;
  }

  if (data.length !== exColCount) {
    alert('Error: Number of data points (' + data.length + ') does not match the number of existing columns (' + exColCount + ').');
    return;
  }

  var newRow = $('<tr></tr>');
  data.forEach(function(item) {
    newRow.append('<td>' + item + '</td>');
  });

  if (index === 0) {
    tbody.prepend(newRow);
  } else {
    tbody.find('tr').eq(index - 1).after(newRow);
  }
}

$(document).ready(function() {
  // Remove row on click
  $(document).on('click', '#myTableBody tr', function() {
    $(this).remove();
  });

  $('#addBtn').click(function() {
    addRow(['Charlie', '35', 'Paris'], 1, 'myTableBody');
  });
});"
