js_content = """function calculate() {
    const num1Str = document.getElementById('num1').value;
    const num2Str = document.getElementById('num2').value;
    const op = document.getElementById('operator').value;
    const banner = document.getElementById('message-banner');
    const display = document.getElementById('result-display');

    banner.className = 'banner hidden';
    display.innerText = '';

    const showMsg = (msg, type) => {
        banner.innerText = msg;
        banner.className = `banner ${type}`;
    };

    if (num1Str === '' || num2Str === '' || op === '') {
        return showMsg('Please fill all fields', 'error');
    }

    const n1 = parseFloat(num1Str);
    const n2 = parseFloat(num2Str);

    if (isNaN(n1) || isNaN(n2)) {
        return showMsg('Please enter valid numbers in the numeric fields', 'error');
    }

    let result;
    switch (op) {
        case '+': result = n1 + n2; break;
        case '-': result = n1 - n2; break;
        case '*': result = n1 * n2; break;
        case '/': 
            if (n2 === 0) return showMsg('Error: Division by zero is not allowed', 'error');
            result = n1 / n2;
            break;
        default: return showMsg('Invalid operator. Use +, -, *, or /', 'error');
    }

    showMsg('Calculation successful!', 'success');
    display.innerText = `Result: ${result}`;
}"""
