const fs = require('fs');

function embedJsInSvg(svgPath, jsPath, outputPath) {
    try {
        const svgContent = fs.readFileSync(svgPath, 'utf8');
        const jsContent = fs.readFileSync(jsPath, 'utf8');

        // Basic validation: check if SVG tag exists
        if (!svgContent.includes('<svg')) {
            throw new Error('Invalid SVG file');
        }

        const scriptTag = `\n<script type=\"text/ecmascript\">\n<![CDATA[\n${jsContent}\n]]>\n</script>\n`;

        // Insert script tag before the closing </svg> tag
        const updatedSvg = svgContent.replace(/<\/svg>/i, `${scriptTag}</svg>`);

        fs.writeFileSync(outputPath, updatedSvg);
        return { success: true, path: outputPath };
    } catch (err) {
        return { success: false, error: err.message };
    }
}

module.exports = { embedJsInSvg };
"""
