app_code = """from flask import Flask, render_template, request, jsonify
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///recipes.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class Recipe(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    ingredients = db.Column(db.Text, nullable=False)
    cuisine = db.Column(db.String(50))
    dietary_restrictions = db.Column(db.String(100))
    calories = db.Column(db.Integer)
    cooking_time = db.Column(db.Integer)

class Favorite(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    recipe_id = db.Column(db.Integer, db.ForeignKey('recipe.id'))

class ShoppingList(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    item = db.Column(db.String(100))

with app.app_context():
    db.create_all()

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/search')
def search():
    query = request.args.get('q', '')
    cuisine = request.args.get('cuisine')
    max_calories = request.args.get('calories', type=int)
    max_time = request.args.get('time', type=int)
    diet = request.args.get('diet')

    results = Recipe.query.filter(Recipe.ingredients.contains(query))
    if cuisine: results = results.filter(Recipe.cuisine == cuisine)
    if max_calories: results = results.filter(Recipe.calories <= max_calories)
    if max_time: results = results.filter(Recipe.cooking_time <= max_time)
    if diet: results = results.filter(Recipe.dietary_restrictions.contains(diet))

    return jsonify([{'id': r.id, 'name': r.name} for r in results.all()])

@app.route('/favorite/<int:rid>', methods=['POST'])
def add_favorite(rid):
    fav = Favorite(recipe_id=rid)
    db.session.add(fav)
    db.session.commit()
    return jsonify({'status': 'added'})

@app.route('/shopping-list', methods=['POST'])
def generate_list():
    recipe_ids = request.json.get('ids', [])
    recipes = Recipe.query.filter(Recipe.id.in_(recipe_ids)).all()
    all_ingredients = []
    for r in recipes:
        all_ingredients.extend(r.ingredients.split(','))

    for item in set(all_ingredients):
        db.session.add(ShoppingList(item=item.strip()))
    db.session.commit()
    return jsonify({'status': 'generated'})

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')
"""

