func NumEquality(m, n, p int, op string) bool {
    if m >= 0 && n >= 0 && p >= 0 {
        switch op {
        case "+":
            return m + n == p
        case "-":
            return m - n == p
        case "*":
            return m * n == p
        case "/":
            if n != 0 {
