    public Map<String, Integer> histogram(String test) {
        Map<String, Integer> frequencyMap = new HashMap<>();
        String[] stringParts = test.split(" ");

        String lastCharacter = null;
        for (String part : stringParts) {
            if (part.equals("#") && lastCharacter != null) {
                // multiply the count of lastCharacter by itself 
                int currentCount = frequencyMap.getOrDefault(lastCharacter, 0);
                frequencyMap.put(lastCharacter, currentCount * currentCount);
            } else if (part.equals("&") && lastCharacter != null) {
                // square the total frequency of lastCharacter
                int currentCount = frequencyMap.getOrDefault(lastCharacter, 0);
                frequencyMap.put(lastCharacter, currentCount * currentCount);
            } else if (Character.isLetter(part.charAt(0))) {
                // counting frequency of letters
                frequencyMap.put(part, frequencyMap.getOrDefault(part, 0) + 1);
                lastCharacter = part;
