        // finding all the letters with highest frequency
        int maxFrequency = 0;
        for (Integer frequency : frequencyMap.values()) {
            if (frequency > maxFrequency) {
                maxFrequency = frequency;
            }
        }

        Map<String, Integer> result = new HashMap<>();
        for (String letter : frequencyMap.keySet()){
            if (frequencyMap.get(letter) == maxFrequency){
