Thought: Now I will implement the server logic in `server.js`. I'll use an in-memory array to store the notes and define the GraphQL schema with the requested Query (getNotes) and Mutations (addNote, editNote, removeNote).
<code>
content = "const express = require('express');
const { ApolloServer, gql } = require('apollo-server-express');

let notes = [];

const typeDefs = gql`
  type Note {
    id: Int!
    title: String!
    description: String!
  }

  type Query {
    getNotes: [Note!]
  }

  type Mutation {
    addNote(title: String!, description: String!): Note!
    editNote(id: Int!, title: String!, description: String!): Note
    removeNote(id: Int!): Boolean
  }
`;

const resolvers = {
  Query: {
    getNotes: () => notes,
  },
  Mutation: {
    addNote: (_, { title, description }) => {
      const newNote = { id: notes.length + 1, title, description };
      notes.push(newNote);
      return newNote;
    },
    editNote: (_, { id, title, description }) => {
      const noteIndex = notes.findIndex(note => note.id === id);
      if (noteIndex === -1) throw new Error('Note not found');
      notes[noteIndex] = { id, title, description };
      return notes[noteIndex];
    },
    removeNote: (_, { id }) => {
      const initialLength = notes.length;
      notes = notes.filter(note => note.id !== id);
      return notes.length < initialLength;
    },
  },
};

async function startServer() {
  const app = express();
  const server = new ApolloServer({ typeDefs, resolvers });
  await server.start();
  server.applyMiddleware({ app });

  app.listen({ port: 4000 }, () => {
    console.log(`🚀 Server ready at http://localhost:4000${server.graphqlPath}`);
  });
}

startServer();
"
