content = "from decimal import Decimal, getcontext

def calculate_fib_number(n):
    # Initialize first two Fibonacci Numbers 
    fib_0 = Decimal(0)
    fib_1 = Decimal(1)

    if (n < 1): 
        return Decimal(0)

    for _ in range(2 , n + 1):
        fib_n = fib_0 + fib_1
        fib_0 = fib_1
        fib_1 = fib_n

    return fib_1

def golden_ratio(n):
    getcontext().prec = n + 5  # Set precision slightly higher to avoid rounding errors
    fib_n = calculate_fib_number(n)
    fib_n1 = calculate_fib_number(n-1)
    if fib_n1 == 0:
        return Decimal(0)
    golden_number = fib_n / fib_n1      
    return round(golden_number, n)

if __name__ == '__main__':
    digit = 5
    print(f'The Golden ratio till the {digit}-th digit: {golden_ratio(digit)}')
    print(f'The corresponding {digit}-th Fibonacci number: {calculate_fib_number(digit)}')
"
