        self.data = data
        self.left = None
        self.right = None
        self.count = 1

class BinarySearchTree:
    def __init__(self, cmp_func):
        self.root = None
        self.cmp_func = cmp_func
        self.size = 0

    def insert(self, data):
        self.size += 1
        if self.root is None:
            self.root = Node(data)
        else:
            self._insert(data, self.root)

    def _insert(self, data, node):
        res = self.cmp_func(data, node.data)
        if res == -1:
            if node.left:
                self._insert(data, node.left)
            else:
                node.left = Node(data)
        elif res == 1:
            if node.right:
                self._insert(data, node.right)
            else:
                node.right = Node(data)
        else:
            node.count += 1

    def get_element_at_index(self, index):
        # In-order traversal to find the k-th element
        stack = []
        curr = self.root
        count = 0
        while stack or curr:
            if curr:
                stack.append(curr)
                curr = curr.left
            else:
                curr = stack.pop()
                count += curr.count
                if count > index:
                    return curr.data
                curr = curr.right
        return None

def versatile_median(l: list, cmp_func: callable):
    if not l:
        raise ValueError("List is empty")

    bst = BinarySearchTree(cmp_func)
    for item in l:
        # Basic validation to ensure it's a number or a tuple of numbers
        if not isinstance(item, (int, float, tuple)):
            raise TypeError(f"Unsupported data type: {type(item)}")
        if isinstance(item, tuple):
            if not all(isinstance(x, (int, float)) for x in item):
                raise TypeError("Tuple must contain only numbers")
        bst.insert(item)

    n = bst.size
    if n % 2 == 1:
        return bst.get_element_at_index(n // 2)
    else:
        m1 = bst.get_element_at_index(n // 2 - 1)
        m2 = bst.get_element_at_index(n // 2)
        # For the median of an even set, we return the average if they are numbers
        # or a tuple of the two middle elements if they aren't easily averageable
        try:
            return (m1 + m2) / 2
        except TypeError:
            return (m1, m2)

# Example comparison function as requested
