    }
}

interface C {
    default void display() {
        System.out.println("Class C");
    }
    default void show() {
        System.out.println("Show method of Class C");
    }
}

class D extends A implements B, C {
    @Override
    public void display() {
        B.super.display();  // Resolving conflict by calling B's version
        C.super.display();  // Resolving conflict by calling C's version
        super.display();    // Calling A's version
    }

    @Override
    public void show() {
        B.super.show();
        C.super.show();
        super.show();
    }

