```cpp
#include <iostream>
#include <vector>
#include <algorithm>

template <class T>
class Tracker {
private:
    std::vector<T> list;
public:

    // Insert elements into the list
    void insert(const T& element) {
        list.push_back(element);
    }

    // Delete a specific element from the list
    bool deleteElement(const T& element) {
        auto it = std::find(list.begin(), list.end(), element);
        if(it != list.end()) {
            list.erase(it);
            return true;
        }
        return false;
    }

    // Track an element in the list
    bool track(const T& element) {
        auto it = std::find(list.begin(), list.end(), element);
        if(it != list.end()) {
            return true;
        }
        return false;
    }

    // Display all elements in the list
    void display() {
        for(auto i: list) {
            std::cout << i << " ";
        }
        std::cout << "\n";
    }
};

int main() {
    Tracker<int> tracker;

    tracker.insert(5);
    tracker.insert(10);
    tracker.insert(15);

    tracker.display();

    tracker.deleteElement(10);

    tracker.display();

    std::cout << (tracker.track(15) ? "Element found" : "Element not found") << "\n";
