               Math.abs(this.humidity - other.humidity) <= tolerance &&
               Math.abs(this.windVelocity - other.windVelocity) <= tolerance &&
               Math.abs(this.pressure - other.pressure) <= tolerance &&
               Math.abs(this.precipitation - other.precipitation) <= tolerance;
