    """
    check if integer n is a prime
    """
    if not isinstance(n, int):
        raise TypeError('Input must be an integer')
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    max_divisor = int(n ** 0.5) + 1
    for d in range(3, max_divisor, 2):
        if n % d == 0:
