Thought: The user wants a C++ implementation of an AVL tree that supports a custom comparator for node comparison. I will implement this by creating a template-based AVL tree class where the comparator is passed as a functional object. I'll write the code to a file, compile it, and verify it works.
<code>
code = """#include <iostream>
#include <functional>
#include <algorithm>

template <typename T, typename Compare = std::less<T>>
class AVLTree {
    struct Node {
        T data;
        Node *left, *right;
        int height;
        Node(T val) : data(val), left(nullptr), right(nullptr), height(1) {}
    };

    Node* root = nullptr;
    Compare comp;

    int getHeight(Node* n) { return n ? n->height : 0; }
    int getBalance(Node* n) { return n ? getHeight(n->left) - getHeight(n->right) : 0; }

    Node* rotateRight(Node* y) {
        Node* x = y->left;
        Node* T2 = x->right;
        x->right = y;
        y->left = T2;
        y->height = std::max(getHeight(y->left), getHeight(y->right)) + 1;
        x->height = std::max(getHeight(x->left), getHeight(x->right)) + 1;
        return x;
    }

    Node* rotateLeft(Node* x) {
        Node* y = x->right;
        Node* T2 = y->left;
        y->left = x;
        x->right = T2;
        x->height = std::max(getHeight(x->left), getHeight(x->right)) + 1;
        y->height = std::max(getHeight(y->left), getHeight(y->right)) + 1;
        return y;
    }

    Node* insert(Node* node, T key) {
        if (!node) return new Node(key);
        if (comp(key, node->data))
            node->left = insert(node->left, key);
        else if (comp(node->data, key))
            node->right = insert(node->right, key);
        else return node;

        node->height = 1 + std::max(getHeight(node->left), getHeight(node->right));
        int balance = getBalance(node);

        if (balance > 1 && comp(key, node->left->data)) return rotateRight(node);
        if (balance < -1 && comp(node->right->data, key)) return rotateLeft(node);
        if (balance > 1 && comp(node->left->data, key)) {
            node->left = rotateLeft(node->left);
            return rotateRight(node);
        }
        if (balance < -1 && comp(key, node->right->data)) {
            node->right = rotateRight(node->right);
            return rotateLeft(node);
        }
        return node;
    }

    void inOrder(Node* root, std::ostream& os) {
        if (!root) return;
        inOrder(root->left, os);
        os << root->data << " ";
        inOrder(root->right, os);
    }

public:
    void insert(T key) { root = insert(root, key); }
    void print(std::ostream& os) { inOrder(root, os); }
};

int main() {
    // Custom comparator: descending order
    AVLTree<int, std::greater<int>> tree;
    tree.insert(10);
    tree.insert(20);
    tree.insert(30);
    tree.insert(5);
    std::cout << "AVL Tree (Descending): ";
    tree.print(std::cout);
    std::cout << std::endl;
    return 0;
}"""
