content = "import urllib.parse
import collections

class URLManager:
    def __init__(self):
        self.error_log = []
        self.supported_protocols = ['http', 'https', 'sftp']

    def encode_component(self, text):
        if text is None: return ""
        return urllib.parse.quote(text)

    def validate_components(self, protocol, subdomain, domain, ccTLD, path, params, fragment, method):
        errors = []
        if protocol not in self.supported_protocols:
            errors.append(f"Unsupported protocol: {protocol}")
        if not subdomain or not domain or not ccTLD:
            errors.append("Missing necessary domain components (subdomain, domain, or ccTLD)")
        if not path or not path.startswith('/'):
            errors.append("Invalid or missing resource path")
        if method not in ['GET', 'POST']:
            errors.append(f"Unsupported or missing request method: {method}")

        if isinstance(params, dict):
            for k, v in params.items():
                if k is None or v is None:
                    errors.append("Query-parameter key or value is missing")

        return errors

    def construct_url(self, protocol, subdomain, domain, ccTLD, path, params={}, fragment=None):
        netloc = f"{self.encode_component(subdomain)}.{self.encode_component(domain)}{ccTLD}"
        query = urllib.parse.urlencode(params)
        url = urllib.parse.urlunparse((protocol, netloc, path, None, query, fragment))
        return url

    def parse_url(self, url):
        parsed = urllib.parse.urlparse(url)
        return {
            'scheme': parsed.scheme,
            'netloc': parsed.netloc,
            'path': parsed.path,
            'params': urllib.parse.parse_qs(parsed.query),
            'fragment': parsed.fragment
        }

    def get_error_counts(self):
        return collections.Counter(self.error_log)

    def get_solutions(self, error_msg):
        solutions = {
            "Unsupported protocol": "Use http, https, or sftp.",
            "Missing necessary domain components": "Ensure subdomain, domain, and ccTLD are provided.",
