        }
        for key, sol in solutions.items():
            if key in error_msg: return sol
        return "Check URL syntax and components."

    def summarize_errors(self):
        counts = self.get_error_counts()
        summary = {err: {"count": counts[err], "solution": self.get_solutions(err)} for err in counts}
        return summary

    def run(self, protocol, subdomain, domain, ccTLD, path, params, fragment, method):
        errors = self.validate_components(protocol, subdomain, domain, ccTLD, path, params, fragment, method)
        if errors:
            self.error_log.extend(errors)
            return False, errors

        url = self.construct_url(protocol, subdomain, domain, ccTLD, path, params, fragment)
        return True, url
