content = """function showResult(text) {
    const section = document.getElementById('resultSection');
    const output = document.getElementById('output');
    section.style.display = 'block';
    output.innerText = text;
}

function handleReverseWords() {
    const text = document.getElementById('inputText').value;
    if (!text) return showResult('Please enter some text.');
    const words = text.trim().split(/\s+/);
    const reversed = words.reverse().join(' ');
    showResult(`Reversed Words: \n${reversed}`);
}

function handlePalindromeCheck() {
    const text = document.getElementById('inputText').value;
    if (!text) return showResult('Please enter some text.');

    const cleanText = text.toLowerCase().replace(/[^a-z0-9]/g, '');
    const isFullPalindrome = cleanText === cleanText.split('').reverse().join('');

    const words = text.split(/\s+/);
    let palindromeCount = 0;
    words.forEach(word => {
        const cleanWord = word.toLowerCase().replace(/[^a-z0-9]/g, '');
        if (cleanWord && cleanWord === cleanWord.split('').reverse().join('')) {
            palindromeCount++;
        }
    });

    showResult(`Full Text Palindrome: ${isFullPalindrome ? 'Yes' : 'No'} \nPalindrome Word Count: ${palindromeCount}`);
}

function handlePigLatin() {
    const text = document.getElementById('inputText').value;
    if (!text) return showResult('Please enter some text.');

    const translate = (word) => {
        if (!word) return '';
        const lowerWord = word.toLowerCase();
        if (/[aeiou]/.test(lowerWord[0])) {
            return lowerWord + 'ay';
        } else {
            const firstVowelIndex = lowerWord.search(/[aeiou]/);
            if (firstVowelIndex === -1) return lowerWord + 'ay';
            return lowerWord.slice(firstVowelIndex) + lowerWord.slice(0, firstVowelIndex) + 'ay';
        }
    };

    const translated = text.split(/\s+/).map(translate).join(' ');
    showResult(`Pig Latin: \n${translated}`);
}"""
