<code>
content = "class Rectangle:
    # Constructor
    def __init__(self, length, width, rgb_color):
        self.__length = None
        self.__width = None
        self.__rgb_color = None

        # Use setters for initial validation
        self.length = length
        self.width = width
        self.rgb_color = rgb_color

    # Properties - Getters/Setters

    @property
    def length(self):
        return self.__length

    @length.setter
    def length(self, value):
        if not isinstance(value, (int, float)) or value <= 0:
            raise ValueError("Length must be a positive number")
        self.__length = value

    @property
    def width(self):
        return self.__width

    @width.setter
    def width(self, value):
        if not isinstance(value, (int, float)) or value <= 0:
            raise ValueError("Width must be a positive number")
        self.__width = value

    @property
    def rgb_color(self):
        return self.__rgb_color

    @rgb_color.setter
    def rgb_color(self, value):
        if not self.__is_valid_rgb(value):
            raise ValueError("Invalid RGB value: must be a tuple of 3 integers between 0-255")
        self.__rgb_color = value

    # Validation function for RGB
    @staticmethod
    def __is_valid_rgb(value):
        if isinstance(value, tuple) and len(value) == 3:
            return all(isinstance(i, int) and 0 <= i <= 255 for i in value)
        return False
"
